public static long solve(long[] nums) {

    int n = nums.length;

    if (n == 0) return 0;

    int maxNum = 1000000;

    int[] spf = new int[maxNum + 1];

    for (int i = 2; i <= maxNum; i++) {

        if (spf[i] == 0) {

            spf[i] = i;

            for (int j = i * 2; j <= maxNum; j += i) {

                if (spf[j] == 0) {

                    spf[j] = i;

                }

            }

        }

    }

    // Now, build the primeToIndices map.

    Map<Integer, List<Integer>> primeToIndices = new HashMap<>();

    for (int i = 0; i < n; i++) {

        long num = nums[i];

        if (num < 2) {

            continue;

        }

        int x = (int) num;

        if (x < 2) {

            continue;

        }

        Set<Integer> primes = new HashSet<>();

        while (x != 1) {

            int p = spf[x];

            primes.add(p);

            while (x % p == 0) {

                x /= p;

            }

        }

        for (int p : primes) {

            primeToIndices.putIfAbsent(p, new ArrayList<>());

            primeToIndices.get(p).add(i);

        }

    }

    // BFS

    int[] dist = new int[n];

    Arrays.fill(dist, -1);

    dist[0] = 0;

    Queue<Integer> q = new LinkedList<>();

    q.add(0);

    while (!q.isEmpty()) {

        int curr = q.poll();

        if (curr == n - 1) {

            return dist[curr];

        }

        // Check adjacent

        for (int next : new int[]{-1, 1}) {

            int neighbor = curr + next;

            if (0 <= neighbor && neighbor < n) {

                if (dist[neighbor] == -1) {

                    dist[neighbor] = dist[curr] + 1;

                    q.add(neighbor);

