            List<Integer> indices = primeToIndices.get(x);

            if (indices != null) {

                for (int j : indices) {

                    if (j != curr && dist[j] == -1) {

                        dist[j] = dist[curr] + 1;

                        q.add(j);

                    }

                }

            }

        }

    }

    return -1; // should not reach here.

